  @fn print(...)  @ 14
  @fn hex(s, alpha)  @ 18
  @fn copy(v)  @ 155
  -- PRIVATE DATA
  -- STORAGE BACKENDS
  @fn pruneUnknown(tbl)  @ 188
      -- Tolerant on load: stale keys from a rename shouldn't error.
  @fn parse(text)  @ 196
      @contract  parse failures (bad text or non-table result) fall through to {}; never raises
  @fn loadGlobal()  @ 203
  @fn saveGlobal(tbl)  @ 211
  @fn loadProject()  @ 221
  @fn saveProject(tbl)  @ 226
